css:
* {
  box-sizing: border-box !important;
}

html, body {
  min-height: 100vh !important;
  background: #0a050a !important;
  color: #d0b8c8 !important;
  font-family: 'Georgia', 'Times New Roman', serif !important;
}

body::before {
  content: '' !important;
  position: fixed !important;
  top: 0 !important;
  left: 0 !important;
  width: 100% !important;
  height: 100% !important;
  z-index: -1 !important;
  background: 
    radial-gradient(circle at 20% 30%, rgba(60,20,40,0.5) 0%, transparent 60%),
    radial-gradient(circle at 80% 70%, rgba(40,10,30,0.6) 0%, transparent 50%),
    radial-gradient(circle at 50% 50%, #0a050a 0%, #100810 100%);
  background-blend-mode: overlay !important;
}

body::after {
  content: '' !important;
  position: fixed !important;
  top: 0 !important;
  left: 0 !important;
  width: 100% !important;
  height: 100% !important;
  z-index: -1 !important;
  pointer-events: none !important;
  background-image: 
    radial-gradient(1px 1px at 10% 10%, rgba(180,140,200,0.2), transparent),
    radial-gradient(1px 1px at 30% 60%, rgba(200,160,220,0.15), transparent),
    radial-gradient(1px 1px at 60% 20%, rgba(160,120,180,0.2), transparent),
    radial-gradient(1px 1px at 80% 80%, rgba(200,170,210,0.15), transparent),
    radial-gradient(1px 1px at 5% 90%, rgba(180,140,200,0.2), transparent),
    radial-gradient(1px 1px at 95% 15%, rgba(200,160,220,0.15), transparent),
    radial-gradient(1px 1px at 45% 45%, rgba(170,130,190,0.2), transparent),
    radial-gradient(1px 1px at 70% 55%, rgba(190,150,210,0.15), transparent);
  background-size: 100% 100%, 100% 100%, 100% 100%, 100% 100%, 100% 100%, 100% 100%, 100% 100%, 100% 100%;
  background-repeat: no-repeat;
  animation: constellationGlow 15s ease-in-out infinite alternate !important;
}

@keyframes constellationGlow {
  0% { opacity: 0.6; }
  100% { opacity: 1; }
}

/* Canvas теперь на заднем плане, под контентом */
#ink-canvas-layer {
  position: fixed !important;
  top: 0 !important;
  left: 0 !important;
  width: 100% !important;
  height: 100% !important;
  z-index: 1 !important;
  pointer-events: none !important;
  background: transparent !important;
}

.p-pageWrapper,
.p-body,
.p-body-inner,
.p-body-main,
.p-body-content,
.p-body-pageContent,
.p-body-header,
.pageContent,
.p-body-inner {
  background: transparent !important;
}

/* Контент выше canvas */
.p-body-inner {
  background: rgba(16, 8, 16, 0.85) !important;
  backdrop-filter: blur(12px) !important;
  -webkit-backdrop-filter: blur(12px) !important;
  border-radius: 36px 36px 24px 24px !important;
  padding: 24px !important;
  box-shadow: 0 8px 64px rgba(0,0,0,0.8), inset 0 0 80px rgba(80,30,60,0.1) !important;
  border: 1px solid rgba(180,100,140,0.15) !important;
  margin: 16px auto !important;
  position: relative;
  z-index: 2;
  overflow: hidden;
}

.p-body-inner::before {
  content: '' !important;
  position: absolute !important;
  top: -4px !important;
  left: -4px !important;
  right: -4px !important;
  bottom: -4px !important;
  border-radius: 40px 40px 28px 28px !important;
  background: 
    repeating-linear-gradient(45deg, 
      rgba(180,100,140,0.05) 0px, 
      rgba(180,100,140,0.05) 4px, 
      transparent 4px, 
      transparent 8px),
    repeating-linear-gradient(-45deg, 
      rgba(160,80,120,0.05) 0px, 
      rgba(160,80,120,0.05) 4px, 
      transparent 4px, 
      transparent 8px) !important;
  z-index: -1 !important;
  pointer-events: none !important;
}

.p-header {
  background: rgba(16, 8, 16, 0.7) !important;
  backdrop-filter: blur(8px) !important;
  border-bottom: 1px solid rgba(180,100,140,0.2) !important;
  border-radius: 36px 36px 0 0 !important;
  padding: 12px 24px !important;
  box-shadow: 0 4px 30px rgba(0,0,0,0.6) !important;
}

.p-header-logo a {
  color: #d48c4b !important;
  font-weight: 700 !important;
  letter-spacing: 1px !important;
  text-shadow: 0 0 30px rgba(212,140,75,0.2) !important;
  font-family: 'Georgia', serif !important;
}

.p-header-logo a:hover {
  text-shadow: 0 0 60px rgba(212,140,75,0.5) !important;
}

.p-nav {
  background: rgba(10, 5, 10, 0.8) !important;
  backdrop-filter: blur(12px) !important;
  border-bottom: 1px solid rgba(180,100,140,0.15) !important;
  box-shadow: 0 4px 32px rgba(0,0,0,0.7) !important;
  padding: 0 16px !important;
}

.p-nav-inner {
  background: transparent !important;
}

.p-nav-list {
  display: flex !important;
  gap: 4px !important;
  background: transparent !important;
}

.p-nav-list .p-navEl {
  color: #b090a0 !important;
  font-weight: 500 !important;
  padding: 12px 20px !important;
  border-radius: 40px !important;
  transition: all 0.3s ease !important;
  background: transparent !important;
  font-family: 'Georgia', serif !important;
  position: relative;
}

.p-nav-list .p-navEl::after {
  content: 'ᛉ' !important;
  position: absolute !important;
  top: 50% !important;
  right: -20px !important;
  transform: translateY(-50%) !important;
  font-size: 12px !important;
  color: rgba(212,140,75,0) !important;
  transition: all 0.3s ease !important;
}

.p-nav-list .p-navEl:hover::after {
  color: rgba(212,140,75,0.6) !important;
  right: -28px !important;
}

.p-nav-list .p-navEl:hover {
  background: rgba(180,100,140,0.15) !important;
  color: #e0c0d0 !important;
  transform: translateY(-2px) !important;
  box-shadow: 0 0 30px rgba(180,100,140,0.1) !important;
  text-shadow: 0 0 20px rgba(212,140,75,0.2) !important;
}

.p-nav-list .p-navEl.is-selected {
  background: rgba(180,100,140,0.2) !important;
  color: #e8c8d8 !important;
  box-shadow: inset 0 0 0 1px rgba(180,100,140,0.3), 0 0 30px rgba(180,100,140,0.1) !important;
  text-shadow: 0 0 20px rgba(212,140,75,0.2) !important;
}

.p-nav-opposite {
  background: transparent !important;
}

.p-navgroup {
  background: transparent !important;
}

.p-navgroup-link {
  color: #b090a0 !important;
  transition: all 0.2s !important;
}

.p-navgroup-link:hover {
  color: #e0c0d0 !important;
  background: rgba(180,100,140,0.1) !important;
  border-radius: 40px !important;
  text-shadow: 0 0 20px rgba(212,140,75,0.1) !important;
}

.block {
  background: rgba(20, 10, 20, 0.6) !important;
  backdrop-filter: blur(8px) !important;
  -webkit-backdrop-filter: blur(8px) !important;
  border-radius: 28px 28px 20px 20px !important;
  border: 1px solid rgba(180,100,140,0.12) !important;
  box-shadow: 0 4px 30px rgba(0,0,0,0.5), inset 0 0 60px rgba(80,30,60,0.05) !important;
  padding: 20px !important;
  margin-bottom: 24px !important;
  transition: all 0.4s cubic-bezier(0.25, 0.46, 0.45, 0.94) !important;
  position: relative;
  overflow: hidden;
}

.block::before {
  content: '' !important;
  position: absolute !important;
  top: -2px !important;
  left: -2px !important;
  right: -2px !important;
  bottom: -2px !important;
  border-radius: 30px 30px 22px 22px !important;
  background: 
    linear-gradient(135deg, rgba(212,140,75,0.08) 0%, transparent 40%, transparent 60%, rgba(212,140,75,0.08) 100%) !important;
  pointer-events: none !important;
  z-index: 0 !important;
}

.block:hover {
  box-shadow: 0 8px 50px rgba(0,0,0,0.7), inset 0 0 60px rgba(180,100,140,0.08) !important;
  transform: translateY(-3px) !important;
  border-color: rgba(180,100,140,0.25) !important;
}

.block-container {
  background: transparent !important;
  border: none !important;
}

.block-body {
  background: transparent !important;
}

.block-minorHeader {
  color: #d48c4b !important;
  font-weight: 600 !important;
  padding: 12px 16px !important;
  border-bottom: 1px solid rgba(180,100,140,0.1) !important;
  text-shadow: 0 0 20px rgba(212,140,75,0.1) !important;
  font-family: 'Georgia', serif !important;
  letter-spacing: 1px;
}

.node {
  background: rgba(26, 12, 22, 0.5) !important;
  border-radius: 24px 24px 16px 16px !important;
  border: 1px solid rgba(180,100,140,0.08) !important;
  padding: 16px 20px !important;
  margin-bottom: 8px !important;
  transition: all 0.3s ease !important;
  position: relative;
}

.node:hover {
  background: rgba(36, 18, 30, 0.7) !important;
  border-color: rgba(180,100,140,0.2) !important;
  transform: translateY(-2px) !important;
  box-shadow: 0 8px 30px rgba(0,0,0,0.4) !important;
}

.node-title a {
  color: #d0b0c0 !important;
  font-weight: 600 !important;
  text-shadow: 0 0 10px rgba(180,100,140,0.05) !important;
}

.node-title a:hover {
  color: #e8c8d8 !important;
  text-shadow: 0 0 30px rgba(212,140,75,0.2) !important;
}

.node-stats {
  color: #907080 !important;
}

.node-extra {
  color: #907080 !important;
}

.node-extra-title {
  color: #a08898 !important;
}

.node-extra-title:hover {
  color: #c0a0b0 !important;
}

.uix_newIndicator {
  background: rgba(180,100,140,0.2) !important;
  color: #d48c4b !important;
  border-radius: 40px !important;
  padding: 2px 12px !important;
  font-size: 11px !important;
  text-shadow: 0 0 10px rgba(212,140,75,0.2) !important;
}

.node-body {
  background: transparent !important;
  display: flex !important;
  align-items: center !important;
  flex-wrap: wrap !important;
  gap: 8px !important;
}

.structItem {
  background: rgba(20, 10, 18, 0.4) !important;
  border-radius: 20px !important;
  border: 1px solid rgba(180,100,140,0.06) !important;
  padding: 12px 16px !important;
  margin-bottom: 6px !important;
  transition: all 0.25s ease !important;
  display: flex !important;
  align-items: stretch !important;
  flex-wrap: nowrap !important;
  gap: 12px !important;
}

.structItem:hover {
  background: rgba(30, 14, 26, 0.6) !important;
  border-color: rgba(180,100,140,0.15) !important;
  box-shadow: 0 4px 20px rgba(0,0,0,0.3) !important;
}

.structItem-cell {
  display: flex !important;
  align-items: center !important;
}

.structItem-cell--icon {
  flex: 0 0 48px !important;
  min-width: 48px !important;
  justify-content: center !important;
}

.structItem-cell--main {
  flex: 1 !important;
  min-width: 0 !important;
  flex-direction: column !important;
  align-items: stretch !important;
}

.structItem-cell--meta {
  flex: 0 0 100px !important;
  justify-content: center !important;
  align-items: flex-start !important;
}

.structItem-cell--latest {
  flex: 0 0 120px !important;
  justify-content: center !important;
  align-items: flex-end !important;
  text-align: right !important;
}

.structItem-cell--iconEnd {
  flex: 0 0 32px !important;
  justify-content: center !important;
}

.structItem-title {
  color: #c8a8b8 !important;
  font-weight: 500 !important;
}

.structItem-title a {
  color: #c8a8b8 !important;
}

.structItem-title a:hover {
  color: #e8c8d8 !important;
  text-shadow: 0 0 30px rgba(212,140,75,0.15) !important;
}

.structItem-statuses {
  color: #907080 !important;
  display: flex !important;
  gap: 4px !important;
  align-items: center !important;
}

.structItem-status--locked {
  color: #cc8888 !important;
}

.structItem-status--sticky {
  color: #d4a06a !important;
}

.structItem-minor {
  color: #807080 !important;
  font-size: 13px !important;
}

.structItem-minor a {
  color: #907080 !important;
}

.structItem-minor a:hover {
  color: #b090a0 !important;
}

.structItem-parts {
  display: flex !important;
  flex-wrap: wrap !important;
  gap: 4px !important;
  margin: 0 !important;
  padding: 0 !important;
  list-style: none !important;
}

.structItem-parts li {
  display: inline !important;
}

.structItem-latestDate {
  color: #907080 !important;
}

.structItem--quickCreate {
  background: rgba(20, 10, 18, 0.2) !important;
  border: 1px dashed rgba(180,100,140,0.15) !important;
  border-radius: 20px !important;
}

.structItem--quickCreate textarea {
  background: rgba(10, 5, 10, 0.6) !important;
  border: 1px solid rgba(180,100,140,0.1) !important;
  color: #d0b8c8 !important;
  border-radius: 20px !important;
  padding: 12px !important;
}

.structItem--quickCreate textarea:focus {
  border-color: rgba(212,140,75,0.3) !important;
  box-shadow: 0 0 0 4px rgba(212,140,75,0.05) !important;
}

.message {
  background: rgba(22, 10, 20, 0.5) !important;
  backdrop-filter: blur(6px) !important;
  border-radius: 28px 28px 20px 20px !important;
  border: 1px solid rgba(180,100,140,0.08) !important;
  padding: 0 !important;
  margin-bottom: 20px !important;
  transition: all 0.3s ease !important;
  overflow: hidden !important;
  position: relative;
}

.message:hover {
  background: rgba(32, 16, 28, 0.65) !important;
  border-color: rgba(180,100,140,0.2) !important;
  box-shadow: 0 8px 40px rgba(0,0,0,0.5) !important;
  transform: translateY(-2px) !important;
}

.message-inner {
  background: transparent !important;
  display: flex !important;
  flex-wrap: wrap !important;
}

.message-cell {
  background: transparent !important;
  padding: 16px !important;
}

.message-cell--user {
  background: rgba(16, 8, 16, 0.3) !important;
  border-right: 1px solid rgba(180,100,140,0.08) !important;
  border-radius: 28px 0 0 20px !important;
  min-width: 180px !important;
  flex: 0 0 180px !important;
}

.message-cell--main {
  flex: 1 !important;
  min-width: 0 !important;
  border-radius: 0 28px 20px 0 !important;
}

.message-user {
  background: transparent !important;
}

.message-avatar {
  text-align: center !important;
  margin-bottom: 8px !important;
}

.message-avatar .avatar {
  border-radius: 50% !important;
  border: 2px solid rgba(180,100,140,0.2) !important;
  transition: all 0.3s ease !important;
  box-shadow: 0 0 20px rgba(180,100,140,0.05) !important;
}

.message-avatar .avatar:hover {
  transform: scale(1.08) !important;
  border-color: rgba(212,140,75,0.4) !important;
  box-shadow: 0 0 40px rgba(212,140,75,0.2) !important;
}

.message-userDetails {
  text-align: center !important;
}

.message-name {
  font-weight: 600 !important;
  font-size: 15px !important;
  font-family: 'Georgia', serif !important;
}

.message-name a {
  color: #d0b0c0 !important;
}

.message-name a:hover {
  color: #e8c8d8 !important;
  text-shadow: 0 0 30px rgba(212,140,75,0.2) !important;
}

.userBanner {
  background: rgba(180,100,140,0.1) !important;
  border-radius: 40px !important;
  padding: 2px 14px !important;
  font-size: 11px !important;
  color: #b090a0 !important;
  display: inline-block !important;
  margin-top: 4px !important;
  text-shadow: 0 0 10px rgba(180,100,140,0.05) !important;
}

.userBanner--red {
  background: rgba(160,60,60,0.15) !important;
  color: #cc8888 !important;
}

.userBanner--primary {
  background: rgba(180,100,140,0.1) !important;
  color: #b090a0 !important;
}

.message-userExtras {
  margin-top: 8px !important;
  font-size: 12px !important;
  color: #807080 !important;
}

.message-userExtras .pairs {
  padding: 2px 0 !important;
}

.message-userExtras .pairs dt {
  color: #706070 !important;
}

.message-userExtras .pairs dd {
  color: #a08898 !important;
}

.message-attribution {
  background: rgba(10, 5, 10, 0.2) !important;
  padding: 8px 16px !important;
  border-bottom: 1px solid rgba(180,100,140,0.04) !important;
}

.message-attribution a {
  color: #807080 !important;
}

.message-attribution a:hover {
  color: #b090a0 !important;
}

.message-newIndicator {
  background: rgba(180,100,140,0.15) !important;
  color: #d48c4b !important;
  border-radius: 40px !important;
  padding: 2px 12px !important;
  font-size: 11px !important;
  text-shadow: 0 0 10px rgba(212,140,75,0.2) !important;
}

.message-content {
  padding: 16px !important;
}

.message-body {
  color: #d0b8c8 !important;
  font-size: 15px !important;
  line-height: 1.7 !important;
}

.message-body .bbWrapper {
  color: #d0b8c8 !important;
}

.message-body a {
  color: #d48c4b !important;
}

.message-body a:hover {
  color: #e8a86a !important;
  text-shadow: 0 0 30px rgba(212,140,75,0.2) !important;
}

.message-body .bbMediaWrapper {
  border-radius: 20px !important;
  overflow: hidden !important;
  background: rgba(10, 5, 10, 0.6) !important;
  border: 1px solid rgba(180,100,140,0.08) !important;
}

.message-body .bbMediaWrapper iframe {
  border-radius: 20px !important;
}

.message-fields--before {
  background: rgba(16, 8, 16, 0.3) !important;
  border-radius: 20px !important;
  padding: 12px 16px !important;
  margin-bottom: 12px !important;
  border: 1px solid rgba(180,100,140,0.06) !important;
}

.message-fields--before .pairs {
  padding: 2px 0 !important;
}

.message-fields--before .pairs dt {
  color: #706070 !important;
  font-weight: 500 !important;
}

.message-fields--before .pairs dd {
  color: #b090a0 !important;
}

.message-signature {
  background: rgba(10, 5, 10, 0.15) !important;
  border-top: 1px solid rgba(180,100,140,0.04) !important;
  padding: 12px 16px !important;
  margin-top: 12px !important;
  border-radius: 0 0 20px 20px !important;
  font-size: 13px !important;
  color: #807080 !important;
  max-height: 100px !important;
  overflow: hidden !important;
  transition: max-height 0.3s ease !important;
}

.message-signature--expanded {
  max-height: 500px !important;
}

.message-signature .bbWrapper {
  color: #807080 !important;
}

.message-signature a {
  color: #a08090 !important;
}

.message-signature a:hover {
  color: #c0a0b0 !important;
}

.uix_signatureExpand {
  cursor: pointer !important;
  color: #706070 !important;
  font-size: 11px !important;
  text-align: center !important;
  padding: 4px !important;
  border-radius: 40px !important;
  background: rgba(180,100,140,0.04) !important;
  margin-bottom: 6px !important;
  transition: all 0.2s !important;
}

.uix_signatureExpand:hover {
  background: rgba(180,100,140,0.08) !important;
  color: #b090a0 !important;
}

.actionBar {
  background: rgba(10, 5, 10, 0.2) !important;
  border-top: 1px solid rgba(180,100,140,0.04) !important;
  padding: 6px 16px !important;
  display: flex !important;
  flex-wrap: wrap !important;
  gap: 4px !important;
  border-radius: 0 0 20px 20px !important;
}

.actionBar-action {
  background: transparent !important;
  color: #807080 !important;
  padding: 4px 12px !important;
  border-radius: 40px !important;
  font-size: 13px !important;
  transition: all 0.2s !important;
  cursor: pointer !important;
}

.actionBar-action:hover {
  background: rgba(180,100,140,0.08) !important;
  color: #c0a0b0 !important;
}

.actionBar-action--reaction {
  background: rgba(180,100,140,0.04) !important;
}

.actionBar-action--reaction:hover {
  background: rgba(180,100,140,0.12) !important;
}

.actionBar-action--menuTrigger {
  color: #706070 !important;
}

.actionBar-action--menuTrigger:hover {
  background: rgba(180,100,140,0.06) !important;
}

.blockStatus {
  background: rgba(16, 8, 16, 0.5) !important;
  border-radius: 40px !important;
  border: 1px solid rgba(180,100,140,0.1) !important;
  padding: 8px 24px !important;
  color: #b090a0 !important;
  backdrop-filter: blur(4px) !important;
  display: inline-flex !important;
  align-items: center !important;
  gap: 8px !important;
}

.blockStatus-message {
  color: #b090a0 !important;
}

.blockStatus-message--locked {
  border-color: #cc6666 !important;
  color: #cc8888 !important;
  background: rgba(160,60,60,0.1) !important;
  border-radius: 40px !important;
  padding: 4px 16px !important;
}

.message-newIndicator,
.uix_newIndicator {
  background: rgba(180,100,140,0.15) !important;
  color: #d48c4b !important;
  border-radius: 40px !important;
  padding: 2px 12px !important;
  font-size: 11px !important;
  font-weight: 600 !important;
  text-shadow: 0 0 10px rgba(212,140,75,0.2) !important;
}

.message--deleted {
  opacity: 0.4 !important;
  background: rgba(160,60,60,0.05) !important;
  border-color: rgba(160,60,60,0.08) !important;
}

.messageNotice--deleted {
  background: rgba(160,60,60,0.04) !important;
  border-radius: 20px !important;
  padding: 12px 16px !important;
  color: #cc8888 !important;
}

.messageNotice--deleted a {
  color: #cc8888 !important;
}

.messageNotice--deleted a:hover {
  color: #ffaaaa !important;
}

.reactionsBar {
  background: rgba(10, 5, 10, 0.2) !important;
