(function() {
  function initInkFlow() {
    const oldCanvas = document.getElementById('ink-canvas-layer');
    if (oldCanvas) oldCanvas.remove();

    const canvas = document.createElement('canvas');
    canvas.id = 'ink-canvas-layer';
    canvas.style.cssText = 'position:fixed;top:0;left:0;width:100%;height:100%;z-index:1;pointer-events:none;background:transparent;';
    document.body.appendChild(canvas);

    const ctx = canvas.getContext('2d');
    let W, H;
    let particles = [];
    const PARTICLE_COUNT = 60; // ещё меньше для производительности
    const CONNECTION_DIST = 180;
    let time = 0;

    function resize() {
      W = canvas.width = window.innerWidth;
      H = canvas.height = window.innerHeight;
    }
    window.addEventListener('resize', resize);
    resize();

    class Particle {
      constructor() {
        this.reset();
        this.type = Math.random() > 0.8 ? 'accent' : 'main';
      }
      reset() {
        this.x = Math.random() * W;
        this.y = Math.random() * H;
        this.vx = (Math.random() - 0.5) * 0.3;
        this.vy = (Math.random() - 0.5) * 0.3;
        this.baseRadius = 1 + Math.random() * 2.5;
        this.opacity = 0.4 + Math.random() * 0.3;
      }
      update(mouse) {
        // Простое движение без лишних вычислений
        if (mouse) {
          const dx = this.x - mouse.x;
          const dy = this.y - mouse.y;
          const dist = Math.sqrt(dx*dx + dy*dy);
          if (dist < 120) {
            const force = (120 - dist) / 120 * 0.3;
            this.vx += (dx / dist) * force;
            this.vy += (dy / dist) * force;
          }
        }
        this.vx += (Math.random() - 0.5) * 0.01;
        this.vy += (Math.random() - 0.5) * 0.01;
        this.vx *= 0.998;
        this.vy *= 0.998;
        this.x += this.vx;
        this.y += this.vy;

        if (this.x < -50) this.x = W + 50;
        if (this.x > W + 50) this.x = -50;
        if (this.y < -50) this.y = H + 50;
        if (this.y > H + 50) this.y = -50;
      }
    }

    for (let i = 0; i < PARTICLE_COUNT; i++) {
      particles.push(new Particle());
    }

    let mouse = null;
    document.addEventListener('mousemove', (e) => {
      mouse = { x: e.clientX, y: e.clientY };
    });
    document.addEventListener('mouseleave', () => { mouse = null; });

    function draw() {
      time++;
      ctx.clearRect(0, 0, W, H);

      // Рисуем линии (без свечения, тонкие)
      for (let i = 0; i < particles.length; i++) {
        for (let j = i + 1; j < particles.length; j++) {
          const dx = particles[i].x - particles[j].x;
          const dy = particles[i].y - particles[j].y;
          const dist = Math.sqrt(dx*dx + dy*dy);
          if (dist < CONNECTION_DIST) {
            const alpha = 1 - (dist / CONNECTION_DIST);
            const isAccent = (particles[i].type === 'accent' || particles[j].type === 'accent');
            // Основная линия — оранжевая, без shadowBlur
            ctx.beginPath();
            ctx.moveTo(particles[i].x, particles[i].y);
            ctx.lineTo(particles[j].x, particles[j].y);
            ctx.strokeStyle = `rgba(255, 180, 80, ${alpha * 0.3})`;
            ctx.lineWidth = 0.6 + alpha * 0.8;
            ctx.stroke();

            // Акцентная линия — золотистая (редко)
            if (isAccent && Math.random() < 0.3) {
              ctx.beginPath();
              ctx.moveTo(particles[i].x, particles[i].y);
              ctx.lineTo(particles[j].x, particles[j].y);
              ctx.strokeStyle = `hsla(40, 100%, 70%, ${alpha * 0.4})`;
              ctx.lineWidth = 1 + alpha * 1.2;
              ctx.stroke();
            }
          }
        }
      }

      // Рисуем частицы (маленькие, без теней)
      for (const p of particles) {
        ctx.beginPath();
        ctx.arc(p.x, p.y, p.baseRadius * 0.8, 0, Math.PI * 2);
        const color = p.type === 'accent'
          ? `rgba(255, 220, 100, ${p.opacity * 0.6})`
          : `rgba(255, 200, 150, ${p.opacity * 0.5})`;
        ctx.fillStyle = color;
        ctx.fill();
        // Лёгкий блик (без shadow)
        ctx.beginPath();
        ctx.arc(p.x - p.baseRadius*0.15, p.y - p.baseRadius*0.15, p.baseRadius*0.2, 0, Math.PI * 2);
        ctx.fillStyle = `rgba(255, 255, 200, ${p.opacity * 0.2})`;
        ctx.fill();
      }

      for (const p of particles) {
        p.update(mouse);
      }

      requestAnimationFrame(draw);
    }

    draw();
  }

  // Эффект свечи (оставляем, но тоже минимальный)
  function initEffects() {
    const container = document.createElement('div');
    container.id = 'witchcraft-effects';
    container.style.cssText = 'position:fixed;top:0;left:0;width:100%;height:100%;pointer-events:none;z-index:1;overflow:hidden;';
    document.body.prepend(container);

    const glow = document.createElement('div');
    glow.style.cssText = `
      position: absolute;
      bottom: 30px;
      right: 30px;
      width: 150px;
      height: 150px;
      background: radial-gradient(circle at 30% 30%, rgba(212,140,75,0.1), rgba(180,100,140,0.03) 70%, transparent 100%);
      border-radius: 50%;
      filter: blur(40px);
      animation: candleFlicker 6s ease-in-out infinite alternate;
    `;
    const style = document.createElement('style');
    style.textContent = `
      @keyframes candleFlicker {
        0% { opacity: 0.2; transform: scale(1) rotate(0deg); }
        50% { opacity: 0.4; transform: scale(1.05) rotate(2deg); }
        100% { opacity: 0.2; transform: scale(0.95) rotate(-2deg); }
      }
    `;
    document.head.appendChild(style);
    container.appendChild(glow);
  }

  initInkFlow();
  initEffects();

  console.log('[Witchcraft] Оптимизированная фоновая версия с оранжевым потоком запущена.');
})();
